import "thirst::time" as t;
glass main() -> Int {
  drink n: Int = t.now();
  pour(n > 0);
  return 0;
}

import "thirst::time" as t;
glass main() -> Int {
  drink ms: Int = t.epoch_ms();
  pour(ms > 1000000);
  return 0;
}

import "thirst::crypto" as crypto;
glass main() -> Int {
  drink h: String = crypto.sha256("hello");
  pour(length(h) == 64);
  return 0;
}

import "thirst::crypto" as crypto;
glass main() -> Int {
  drink s: String = crypto.sign("hello");
  pour(contains(s, "signed:"));
  return 0;
}

import "thirst::crypto" as crypto;
glass main() -> Int {
  drink h: String = crypto.hmac("key", "data");
  pour(length(h) > 0);
  return 0;
}

import "thirst::crypto" as crypto;
glass main() -> Int {
  drink b: String = crypto.random_bytes(8);
  pour(length(b) == 16);
  return 0;
}

import "thirst::crypto" as crypto;
glass main() -> Int {
  drink u: String = crypto.uuid4();
  pour(length(u) == 36);
  return 0;
}

import "thirst::reservoir" as res;
glass main() -> Int {
  drink xs: Reservoir[Int] = [1, 2, 3];
  pour(res.size(xs));
  return 0;
}

import "thirst::reservoir" as res;
glass main() -> Int {
  drink mut xs: Reservoir[Int] = [];
  res.push(xs, 99);
  pour(res.size(xs));
  return 0;
}

import "thirst::reservoir" as res;
glass main() -> Int {
  drink mut xs: Reservoir[Int] = [1, 2, 3];
  drink v: Any = res.pop(xs);
  pour(v);
  return 0;
}

import "thirst::reservoir" as res;
glass main() -> Int {
  drink xs: Reservoir[Int] = [10, 20, 30];
  pour(res.get(xs, 2));
  return 0;
}

import "thirst::reservoir" as res;
glass main() -> Int {
  drink mut xs: Reservoir[Int] = [1];
  res.flood(xs, [2, 3]);
  pour(res.size(xs));
  return 0;
}

import "thirst::fs" as fs;
glass main() -> Int {
  pour(fs.exists("."));
  return 0;
}

import "thirst::fs" as fs;
glass main() -> Int {
  pour(fs.exists("/no/such/path/xyz999"));
  return 0;
}

import "thirst::path" as p;
glass main() -> Int {
  pour(p.basename("/foo/bar/baz.thirsty"));
  return 0;
}

import "thirst::path" as p;
glass main() -> Int {
  pour(p.extension("hello.thirsty"));
  return 0;
}

import "thirst::json" as json;
glass main() -> Int {
  drink s: String = json.stringify(42);
  pour(s);
  return 0;
}

import "thirst::env" as env;
glass main() -> Int {
  drink v: Any = env.get("PATH");
  pour(v != empty);
  return 0;
}

import "thirst::env" as env;
glass main() -> Int {
  drink v: Any = env.get("THIRSTY_NONEXISTENT_XYZ");
  pour(v == empty);
  return 0;
}

import "thirst::process" as proc;
glass main() -> Int {
  drink p: Any = proc.pid();
  pour(p > 0);
  return 0;
}

import "thirst::collections" as col;
glass main() -> Int {
  drink xs: Reservoir[Int] = [1, 2, 3];
  drink ys: Any = col.map(xs, glass(x: Int) -> Int { return x * 10; });
  pour(get(ys, 0));
  return 0;
}

import "thirst::collections" as col;
glass main() -> Int {
  drink xs: Reservoir[Int] = [1, 2, 3, 4];
  drink odds: Any = col.filter(xs, glass(x: Int) -> Bool { return x % 2 != 0; });
  pour(size(odds));
  return 0;
}

import "thirst::collections" as col;
glass main() -> Int {
  drink xs: Reservoir[Int] = [3, 1, 2];
  drink ys: Any = col.sort(xs);
  pour(get(ys, 0));
  return 0;
}

import "thirst::collections" as col;
glass main() -> Int {
  drink xs: Reservoir[Int] = [1, 2, 2, 3, 3, 3];
  drink ys: Any = col.unique(xs);
  pour(size(ys));
  return 0;
}

import "thirst::collections" as col;
glass main() -> Int {
  drink xs: Reservoir[Any] = [[1, 2], [3, 4]];
  drink flat: Any = col.flatten(xs);
  pour(size(flat));
  return 0;
}
